package db

import (
	"context"
	"fmt"
	"strings"
	"time"
)

// ---------------------------------------------------------------------------
// Dynamic usage query — not generated by sqlc because the WHERE clause and
// GROUP BY are built at runtime from caller-supplied filters.
// ---------------------------------------------------------------------------

// UsageFilter carries every knob the caller can turn.
type UsageFilter struct {
	// Time range — both optional, applied to hour_ts (inclusive).
	From *time.Time
	To   *time.Time

	// Proxyset exact match — empty means no filter.
	Proxyset string

	// MetaContains is a raw JSON string used with the JSONB @> (contains)
	// operator against affinity_params.  E.g. `{"user":"alice"}`.
	// Empty means no filter.
	MetaContains string

	// Granularity controls the GROUP BY / SELECT shape.
	Granularity Granularity

	// Pagination — 1-indexed page, 0 or negative → page 1.
	Page     int
	PageSize int
}

// Granularity defines how rows are aggregated.
type Granularity string

const (
	GranularityHour     Granularity = "hour"     // raw hour buckets (default)
	GranularityDay      Granularity = "day"       // aggregate per UTC day
	GranularityProxyset Granularity = "proxyset"  // aggregate per proxyset
	GranularityTotal    Granularity = "total"     // single grand total
)

// UsageRow is the shape returned by QueryUsage regardless of granularity.
// Fields not applicable to a given granularity are zero/nil.
type UsageRow struct {
	HourTS         *time.Time // non-nil for GranularityHour
	Day            *time.Time // non-nil for GranularityDay
	Proxyset       *string    // non-nil for GranularityHour, GranularityDay, GranularityProxyset
	AffinityParams *string    // non-nil for GranularityHour (raw JSON)
	UploadBytes    int64
	DownloadBytes  int64
}

// UsageResult wraps the rows with pagination metadata.
type UsageResult struct {
	Rows       []UsageRow
	TotalCount int64 // total matching rows (before pagination)
	Page       int
	PageSize   int
}

const defaultPageSize = 100
const maxPageSize = 1000

// QueryUsage executes a dynamic filtered+paginated query against the usage table.
func (q *Queries) QueryUsage(ctx context.Context, f UsageFilter) (*UsageResult, error) {
	// ------------------------------------------------------------------ params
	page := f.Page
	if page < 1 {
		page = 1
	}
	pageSize := f.PageSize
	if pageSize < 1 {
		pageSize = defaultPageSize
	}
	if pageSize > maxPageSize {
		pageSize = maxPageSize
	}

	gran := f.Granularity
	if gran == "" {
		gran = GranularityHour
	}

	// ------------------------------------------------------------------ WHERE
	var (
		conds  []string
		args   []any
		argIdx = 1
	)

	placeholder := func(v any) string {
		s := fmt.Sprintf("$%d", argIdx)
		args = append(args, v)
		argIdx++
		return s
	}

	if f.From != nil {
		conds = append(conds, "hour_ts >= "+placeholder(*f.From))
	}
	if f.To != nil {
		conds = append(conds, "hour_ts <= "+placeholder(*f.To))
	}
	if f.Proxyset != "" {
		conds = append(conds, "proxyset = "+placeholder(f.Proxyset))
	}
	if f.MetaContains != "" {
		conds = append(conds, "affinity_params @> "+placeholder([]byte(f.MetaContains)))
	}

	where := ""
	if len(conds) > 0 {
		where = "WHERE " + strings.Join(conds, " AND ")
	}

	// ------------------------------------------------------------------ SELECT / GROUP BY
	var selectCols, groupBy, orderBy string

	switch gran {
	case GranularityHour:
		selectCols = "hour_ts, proxyset, affinity_params::text, SUM(upload_bytes), SUM(download_bytes)"
		groupBy = "GROUP BY hour_ts, proxyset, affinity_params"
		orderBy = "ORDER BY hour_ts DESC, proxyset"
	case GranularityDay:
		selectCols = "date_trunc('day', hour_ts AT TIME ZONE 'UTC') AS day, proxyset, SUM(upload_bytes), SUM(download_bytes)"
		groupBy = "GROUP BY day, proxyset"
		orderBy = "ORDER BY day DESC, proxyset"
	case GranularityProxyset:
		selectCols = "proxyset, SUM(upload_bytes), SUM(download_bytes)"
		groupBy = "GROUP BY proxyset"
		orderBy = "ORDER BY proxyset"
	case GranularityTotal:
		selectCols = "SUM(upload_bytes), SUM(download_bytes)"
		groupBy = ""
		orderBy = ""
	default:
		return nil, fmt.Errorf("unknown granularity %q (valid: hour, day, proxyset, total)", gran)
	}

	// ------------------------------------------------------------------ COUNT
	// Wrap a SELECT of the grouping columns so aliases are resolved before COUNT.
	countSQL := fmt.Sprintf(`SELECT COUNT(*) FROM (SELECT %s FROM usage %s %s) _c`, selectCols, where, groupBy)
	var totalCount int64
	if err := q.db.QueryRow(ctx, countSQL, args...).Scan(&totalCount); err != nil {
		return nil, fmt.Errorf("usage count query: %w", err)
	}

	// ------------------------------------------------------------------ DATA
	offset := (page - 1) * pageSize
	limitClause := fmt.Sprintf("LIMIT %d OFFSET %d", pageSize, offset)

	dataSQL := fmt.Sprintf(`SELECT %s FROM usage %s %s %s %s`,
		selectCols, where, groupBy, orderBy, limitClause)

	rows, err := q.db.Query(ctx, dataSQL, args...)
	if err != nil {
		return nil, fmt.Errorf("usage data query: %w", err)
	}
	defer rows.Close()

	var result []UsageRow
	for rows.Next() {
		var row UsageRow
		switch gran {
		case GranularityHour:
			var ts time.Time
			var ps string
			var ap string
			if err := rows.Scan(&ts, &ps, &ap, &row.UploadBytes, &row.DownloadBytes); err != nil {
				return nil, fmt.Errorf("usage row scan: %w", err)
			}
			row.HourTS = &ts
			row.Proxyset = &ps
			row.AffinityParams = &ap
		case GranularityDay:
			var day time.Time
			var ps string
			if err := rows.Scan(&day, &ps, &row.UploadBytes, &row.DownloadBytes); err != nil {
				return nil, fmt.Errorf("usage row scan: %w", err)
			}
			row.Day = &day
			row.Proxyset = &ps
		case GranularityProxyset:
			var ps string
			if err := rows.Scan(&ps, &row.UploadBytes, &row.DownloadBytes); err != nil {
				return nil, fmt.Errorf("usage row scan: %w", err)
			}
			row.Proxyset = &ps
		case GranularityTotal:
			if err := rows.Scan(&row.UploadBytes, &row.DownloadBytes); err != nil {
				return nil, fmt.Errorf("usage row scan: %w", err)
			}
		}
		result = append(result, row)
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("usage rows error: %w", err)
	}

	return &UsageResult{
		Rows:       result,
		TotalCount: totalCount,
		Page:       page,
		PageSize:   pageSize,
	}, nil
}
